import numpy as np

def channel_l1_norms(W: np.ndarray) -> np.ndarray:
    return np.sum(np.abs(W), axis=1)

def prune_channels(W: np.ndarray, n_keep: int) -> tuple:
    out_features = W.shape[0]
    if n_keep > out_features:
        raise ValueError(f'n_keep ({n_keep}) > out_features ({out_features})')
    norms = channel_l1_norms(W)
    # Indices sorted by norm descending, take top n_keep
    sorted_idx = np.argsort(norms)[::-1]
    kept_idx = np.sort(sorted_idx[:n_keep])  # sort for deterministic output
    return W[kept_idx], kept_idx

def prune_channels_by_ratio(W: np.ndarray, keep_ratio: float) -> tuple:
    n_keep = max(1, int(W.shape[0] * keep_ratio))
    return prune_channels(W, n_keep)

