import torch
import torch.nn as nn

def channel_l1_norms(W: torch.Tensor) -> torch.Tensor:
    return torch.sum(W.abs(), dim=1)

def prune_channels(W: torch.Tensor, n_keep: int) -> tuple:
    out_features = W.size(0)
    if n_keep > out_features:
        raise ValueError(f'n_keep ({n_keep}) > out_features ({out_features})')
    norms = channel_l1_norms(W)
    _, sorted_idx = torch.sort(norms, descending=True)
    kept_idx = torch.sort(sorted_idx[:n_keep]).values
    return W[kept_idx], kept_idx

def prune_channels_by_ratio(W: torch.Tensor, keep_ratio: float) -> tuple:
    n_keep = max(1, int(W.size(0) * keep_ratio))
    return prune_channels(W, n_keep)
